why not just have a single `parseTokens` function for both?

```ts
const parseTokens = (text: string) => {
  const tokens = [];
  let buffer = '';

  for (let i = 0; i < text.length; i++) {
    const char = text[i];

    if (char === ' ' || char === '-') {
      if (char === '-') {
        buffer += char;
      }
      if (buffer.length > 0) {
        tokens.push(buffer);
        buffer = '';
      }
    } else {
      buffer += char;
    }
  }

  if (buffer.length > 0) {
    tokens.push(buffer);
  }

  return tokens;
}
```
